mapper.select:
select b.id, b.user_id, b.black_user_id, b.created_at, IFNULL(um.idno, '') AS user_idno, IFNULL(um.nickname, '') AS user_nickname, IFNULL(bm.idno, '') AS black_user_idno, IFNULL(bm.nickname, '') AS black_user_nickname from t_piamom_user_blacklist b left join t_member um on um.id = b.user_id left join t_member bm on bm.id = b.black_user_id
order by ${orderBy} order by b.created_at desc
limit #{pageNo}, #{pageSize}
